import { useEffect, useState, useRef } from 'react';
import api from '../services/api';
import { useSocket } from '../context/SocketContext';
import { formatPrice } from '../utils/formatters';
import Button from '../components/UI/Button';
import notificationSound from '../assets/notification.mp3'; // تأكد من إضافة الملف الصوتي

const DriverDashboard = () => {
  const [orders, setOrders] = useState([]);
  const [loading, setLoading] = useState(true);
  const socket = useSocket();
  const audioRef = useRef(new Audio(notificationSound));

  useEffect(() => {
    fetchOrders();
  }, []);

  useEffect(() => {
    if (!socket) return;
    socket.on('newDeliveryRequest', (data) => {
      audioRef.current.play();
      alert(`طلب جديد! رقم الطلب: ${data.orderId.slice(-6)}`);
      fetchOrders();
    });
    return () => socket.off('newDeliveryRequest');
  }, [socket]);

  const fetchOrders = async () => {
    try {
      const { data } = await api.get('/driver/orders');
      setOrders(data);
    } catch (error) {
      console.error(error);
    } finally {
      setLoading(false);
    }
  };

  const handleDeliver = async (orderId) => {
    try {
      await api.put(`/driver/orders/${orderId}/deliver`);
      fetchOrders();
    } catch (error) {
      alert('فشل تحديث الحالة');
    }
  };

  if (loading) return <div className="p-4">جاري التحميل...</div>;

  return (
    <div dir="rtl" className="container mx-auto p-4">
      <h1 className="text-3xl font-bold mb-6">لوحة المندوب</h1>
      {orders.length === 0 ? (
        <p className="text-gray-600">لا توجد طلبات مسندة إليك حالياً.</p>
      ) : (
        <div className="grid gap-4">
          {orders.map(order => (
            <div key={order._id} className="bg-white rounded-lg shadow-md p-6">
              <div className="flex justify-between items-start">
                <div>
                  <p className="font-bold text-lg">رقم الطلب: #{order._id.slice(-6).toUpperCase()}</p>
                  <p className="text-gray-700">العميل: {order.user?.name}</p>
                  <p className="text-gray-700">الهاتف: {order.phone}</p>
                  <p className="text-gray-700">
                    العنوان: {order.deliveryAddress?.street}، {order.deliveryAddress?.area}
                  </p>
                  <p className="text-gray-700">الإجمالي: {formatPrice(order.totalPrice)}</p>
                  <div className="mt-2">
                    <p className="font-medium">الطلبات:</p>
                    <ul className="list-disc list-inside">
                      {order.items.map((item, idx) => (
                        <li key={idx}>{item.quantity} × {item.name}</li>
                      ))}
                    </ul>
                  </div>
                </div>
                <Button onClick={() => handleDeliver(order._id)} variant="primary">
                  تم التوصيل
                </Button>
              </div>
            </div>
          ))}
        </div>
      )}
    </div>
  );
};

export default DriverDashboard;
